// Define a function to fix the CSS string
function fixCss(cssString) {
  // Parse the CSS string to extract the display property
  const css = cssString.split(');
  const displayProperty = css[0].trim().split(': ').pop();

  // Check if the display property is set to 'inline-grid'
  if (displayProperty === 'inline-grid') {
    // Modify the display property to 'grid'
    css[0] = css[0].replace('inline-grid', 'grid');
  }

  // Join the modified CSS string
  return css.join(');
}

// Test the function with a sample input
console.log(fixCss(".container {
  display: inline-grid;
  grid-template-columns: 100px 200px;
  grid-template-rows: 100px;
}")));

solutions.python:
class Solution:
  def fix_css(self, css_string):
    # Parse the CSS string to extract the display property
    css = css_string.strip().split(');
    display_property = css[0].strip().split(': ').pop()

    # Check if the display property is set to 'inline-grid'
    if display_property == 'inline-grid':
      # Modify the display property to 'grid'
      css[0] = css[0].replace('inline-grid', 'grid')

    # Join the modified CSS string
    return ')'.join(css)

# Test the function with a sample input
solution = Solution()
print(solution.fix_css(".container {
  display: inline-grid;
  grid-template-columns: 100px 200px;
  grid-template-rows: 100px;
}"))
